@app.route('/analytics/documents-by-author', methods=['GET'])
def documents_by_author():
    pipeline = [
        {
            '$group': {
                '_id': '$author_id',
                'total_documents': {'$sum': 1},
                'total_views': {'$sum': '$views'},
                'total_likes': {'$sum': '$likes'},
                'published_count': {
                    '$sum': {'$cond': [{'$eq': ['$status', 'published']}, 1, 0]}
                },
                'draft_count': {
                    '$sum': {'$cond': [{'$eq': ['$status', 'draft']}, 1, 0]}
                }
            }
        },
        {
            '$lookup': {
                'from': 'users',
                'localField': '_id',
                'foreignField': '_id',
                'as': 'author'
            }
        },
        {
            '$unwind': '$author'
        },
        {
            '$project': {
                'author_id': '$_id',
                'author_name': '$author.full_name',
                'author_username': '$author.username',
                'total_documents': 1,
                'total_views': 1,
                'total_likes': 1,
                'published_count': 1,
                'draft_count': 1,
                'avg_views_per_document': {
                    '$cond': [
                        {'$eq': ['$total_documents', 0]},
                        0,
                        {'$divide': ['$total_views', '$total_documents']}
                    ]
                }
            }
        },
        {
            '$sort': {'total_documents': -1}
        }
    ]
    
    results = list(documents_collection.aggregate(pipeline))
    return jsonify({'success': True, 'analytics': results}), 200


